import React from "react"
import Select from 'react-select'
//import Calendar from 'react-select-date'
import { Calendar, DateObject } from "react-multi-date-picker"
import { properties } from '../../properties/properties.js'
import Moment from 'moment'
var xlsx = require("xlsx");
const fs = require('fs');

class Scheduler extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0, selectedFile: null
        };
    }

    handleselectedFile = event => {
        console.log(event.target.files[0])
        this.setState({
          selectedFile: event.target.files[0]
        })
      }


    handleUpload = (e) => {
        e.preventDefault();

/*
        var wb = xlsx.readFile(this.state.selectedFile);


        var wsR1 = wb.Sheets[wb.SheetNames[0]];
        var wsR2 = wb.Sheets[wb.SheetNames[1]];
        var wsR3 = wb.Sheets[wb.SheetNames[2]];


        this.findRotation("UC Card", wsR1)
        */
        var reader = new FileReader();
        reader.onload = function (e) {

            function findRotation(forWhichRotation, ws) {

                var range = xlsx.utils.decode_range(ws['!ref']);

                for (let colNum = 0; colNum <= range.e.c; colNum++) {

                    var rotationRow = findV(ws[xlsx.utils.encode_cell({r: 2, c: colNum})])

                    if (rotationRow.length > 0 && !isNaN(rotationRow.substring(0,1))) {
                       console.log("*******************************************************************")
                       console.log(rotationRow)
                       for (let rowNum = 3; rowNum <= range.e.r; rowNum++) {
                           var isRotation = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colNum})])
                           var data = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: 0})])
                           if (isRotation === forWhichRotation && data != "OB") {
                               var before = ""
                               if (colNum > 1) {
                                   before = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colNum - 1})])
                               }
                               var after = ""
                               var checkClinics = findV(ws[xlsx.utils.encode_cell({r: 2, c: colNum + 1})])
                               if (checkClinics != "Clinics") {
                                   after = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colNum + 1})])
                               }
                               var clinic = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: range.e.c})])
                               var lastColumn = findV(ws[xlsx.utils.encode_cell({r: 2, c: range.e.c})])
                               if (lastColumn === "Clinics") {
                                   clinic = ""
                               }
                               console.log("Name:" + data + " ** before:" + before + " ** rotation:" + forWhichRotation + " ** after:" + after + " ** clinic:" + clinic)

                           }
                       }
                    }

                }
            }




            function findV(cellValue) {
                var value_v = "";
                if (typeof cellValue !== 'undefined')
                    value_v = cellValue.v
                else
                    value_v = ""
                return value_v;
            }

            function findW(cellValue) {
                var value_w = "";
                if (typeof cellValue !== 'undefined') {
                    value_w = Moment(cellValue.w,'M/D/YY').format('MM/DD/YYYY')

                } else {
                    value_w = ""
                }
                return value_w;
            }


            var data = e.target.result;
            let readedData = xlsx.read(data, {type: 'binary'});
            const wsname = readedData.SheetNames[0];
            const ws = readedData.Sheets[wsname];

            /* Convert array to json*/
            //const dataParse = xlsx.utils.sheet_to_json(ws, {header:1});
            //setFileUploaded(dataParse);

            findRotation("UC Card", ws)


        };
        reader.readAsBinaryString(this.state.selectedFile)

      }



    componentDidMount() {




      }


          render() {


            var header = ""

            var content = []
            //var items = []

            content.push(<div >
            <input type="hidden" name="todayDate" value={this.state.todayDay} />
            <input type="file" name="" id="" onChange={this.handleselectedFile} />
            <button onClick={this.handleUpload}>Upload</button>

            <hr></hr>
            <div>

            </div>
          </div>)



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default Scheduler
